        return np.linalg.norm(end_pos - start_pos) / speed

    def calculate_penalty(early_time, late_time, current_time):
        if current_time < early_time:
            return early_time - current_time
        elif current_time > late_time:
            return current_time - late_time
        else:
            return 0

    min_time = float('inf')
    best_node = None

